 3→import {GestureHandlerRootView} from 'react-native-gesture-handler';
 4→import {SafeAreaProvider} from 'react-native-safe-area-context';
 5→import {QueryClientProvider} from '@tanstack/react-query';
 6→import {RootNavigator} from './src/navigation/RootNavigator';
 7→import {queryClient} from './src/lib/queryClient';
 8→import * as authProviderModule from './src/features/auth/AuthProvider';
 9→import {AppErrorBoundary} from './src/components/AppErrorBoundary';
10→import {colors} from './src/theme/colors';
11→
12→function App(): React.JSX.Element {
13→  const AuthProvider = authProviderModule.AuthProvider as
14→    | React.ComponentType<{children: React.ReactNode}>
15→    | undefined;
16→
17→  if (!AuthProvider) {
18→    return (
19→      <GestureHandlerRootView style={styles.root}>
20→        <SafeAreaProvider>
21→          <AppErrorBoundary>
22→            <View style={styles.errorContainer}>
23→              <Text style={styles.errorTitle}>Auth module failed to load</Text>
24→              <Text style={styles.errorBody}>
25→                Restart Metro with --reset-cache and relaunch the app.
26→              </Text>
27→            </View>
28→          </AppErrorBoundary>
29→        </SafeAreaProvider>
30→      </GestureHandlerRootView>
31→    );
32→  }
33→
34→  return (
35→    <GestureHandlerRootView style={styles.root}>
36→      <SafeAreaProvider>
37→        <AppErrorBoundary>
38→          <QueryClientProvider client={queryClient}>
39→            <AuthProvider>
40→              <StatusBar barStyle="light-content" backgroundColor={colors.background} />
41→              <RootNavigator />
42→            </AuthProvider>
43→          </QueryClientProvider>
44→        </AppErrorBoundary>
45→      </SafeAreaProvider>
46→    </GestureHandlerRootView>
47→  );
48→}
49→
50→const styles = StyleSheet.create({
51→  root: {
52→    flex: 1,
53→    backgroundColor: colors.background,
54→  },
55→  errorContainer: {
56→    flex: 1,
57→    alignItems: 'center',
58→    justifyContent: 'center',
59→    paddingHorizontal: 24,
60→    backgroundColor: colors.background,
61→  },
