12→
13→export function PrimaryButton({ label, onPress, loading, disabled, kind = 'primary' }: PrimaryButtonProps) {
14→  const isDisabled = loading || disabled;
15→
16→  return (
17→    <Pressable
18→      disabled={isDisabled}
19→      onPress={onPress}
20→      style={({ pressed }) => [
21→        styles.button,
22→        kind === 'secondary' && styles.secondary,
23→        kind === 'danger' && styles.danger,
24→        isDisabled && styles.disabled,
25→        pressed && !isDisabled && styles.pressed,
26→      ]}
27→    >
28→      {loading ? <ActivityIndicator color={colors.white} /> : <Text style={styles.label}>{label}</Text>}
29→    </Pressable>
30→  );
31→}
