 55→export function PostDetailScreen({route}: Props) {
 56→  const {user, session} = useAuth();
 57→  const {journalId} = route.params;
 58→  const token = session?.access_token ?? '';
 59→  const [commentInput, setCommentInput] = useState('');
 60→  const [repostCaption, setRepostCaption] = useState('');
 61→
 62→  const detailQuery = useQuery({
 63→    queryKey: ['journal', journalId, user?.id],
 64→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
 65→  });
 66→
 67→  const commentsQuery = useQuery({
 68→    queryKey: ['journal-comments', journalId],
 69→    queryFn: () => socialApi.getComments(journalId, null, 20),
 70→  });
 71→
 72→  const likeMutation = useMutation({
 73→    mutationFn: async () => {
 74→      const journal = detailQuery.data?.journal;
 75→      const receiverId = journal?.user_id ?? journal?.users?.id;
 76→      if (!token) {
 77→        throw new Error('Please log in to like this post.');
 78→      }
 79→      if (!journal?.id || !receiverId) {
 80→        throw new Error('Missing journal data.');
 81→      }
 82→
 83→      const metadata = session?.user.user_metadata as
 84→        | {name?: string; avatar_url?: string}
 85→        | undefined;
 86→
 87→      return socialApi.likeJournal(token, {
 88→        journalId: journal.id,
 89→        receiverId,
 90→        sendername: metadata?.name,
 91→        senderImageUrl: metadata?.avatar_url,
 92→        senderEmail: session?.user.email,
 93→      });
 94→    },
 95→    onSuccess: async () => {
 96→      await Promise.all([
 97→        queryClient.invalidateQueries({queryKey: ['journal', journalId]}),
 98→        queryClient.invalidateQueries({queryKey: ['feed']}),
 99→      ]);
100→    },
101→    onError: error => {
102→      Alert.alert(
103→        'Like failed',
104→        error instanceof Error ? error.message : 'Could not update like state.',
105→      );
106→    },
107→  });
108→
109→  const bookmarkMutation = useMutation({
110→    mutationFn: async () => {
111→      if (!token) {
112→        throw new Error('Please log in to bookmark this post.');
113→      }
114→      return socialApi.toggleBookmark(token, {journalId});
115→    },
116→    onSuccess: async () => {
117→      await Promise.all([
118→        queryClient.invalidateQueries({queryKey: ['journal', journalId]}),
119→        queryClient.invalidateQueries({queryKey: ['feed']}),
120→      ]);
121→    },
122→    onError: error => {
123→      Alert.alert(
124→        'Bookmark failed',
125→        error instanceof Error
126→          ? error.message
127→          : 'Could not update bookmark state.',
128→      );
129→    },
130→  });
131→
132→  const addCommentMutation = useMutation({
133→    mutationFn: async () => {
134→      const body = commentInput.trim();
135→      const receiverId =
136→        detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
137→
138→      if (!token) {
139→        throw new Error('Please log in to comment.');
140→      }
141→      if (!body) {
142→        throw new Error('Comment cannot be empty.');
143→      }
144→      if (!receiverId) {
145→        throw new Error('Missing journal owner.');
146→      }
147→
148→      return socialApi.addComment(token, {
149→        comments: body,
150→        postId: journalId,
151→        receiverId,
152→      });
153→    },
154→    onSuccess: async () => {
155→      setCommentInput('');
156→      await Promise.all([
157→        queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]}),
158→        queryClient.invalidateQueries({queryKey: ['journal', journalId]}),
159→        queryClient.invalidateQueries({queryKey: ['feed']}),
160→      ]);
161→    },
162→    onError: error => {
163→      Alert.alert(
164→        'Comment failed',
165→        error instanceof Error ? error.message : 'Could not submit comment.',
166→      );
167→    },
168→  });
169→
170→  const repostMutation = useMutation({
171→    mutationFn: async () => {
172→      if (!token) {
173→        throw new Error('Please log in to repost.');
174→      }
175→      return socialApi.createRepost(token, {
176→        sourceJournalId: journalId,
177→        caption: repostCaption.trim() || undefined,
178→      });
179→    },
180→    onSuccess: async () => {
181→      setRepostCaption('');
182→      Alert.alert('Reposted', 'Post was reposted to your feed.');
183→      await queryClient.invalidateQueries({queryKey: ['feed']});
184→    },
185→    onError: error => {
186→      Alert.alert(
187→        'Repost failed',
188→        error instanceof Error ? error.message : 'Could not repost this post.',
189→      );
190→    },
191→  });
192→
193→  const journal = detailQuery.data?.journal;
194→  const bodyText = useMemo(() => {
195→    const text = extractPlainTextFromLexical(journal?.content);
196→    return text || 'No content available.';
197→  }, [journal?.content]);
198→
199→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
200→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
201→  const bookmarkCount = resolveCount(journal?.bookmark_count);
202→  const comments = commentsQuery.data?.comments ?? [];
203→
204→  return (
205→    <Screen>
206→      {detailQuery.isLoading && (
207→        <View style={styles.loadingRow}>
208→          <ActivityIndicator color={colors.accent} />
209→          <Text style={styles.loadingText}>Loading post...</Text>
210→        </View>
211→      )}
212→
213→      {detailQuery.isError && (
214→        <Text style={styles.error}>Unable to load this post.</Text>
215→      )}
216→
217→      {!!journal && (
218→        <View style={styles.card}>
219→          <Text style={styles.title}>
220→            {journal.title || 'Untitled Post'}
221→          </Text>
222→          <Text style={styles.meta}>
223→            {journal.users?.name || 'Unknown author'}
224→            {journal.created_at
225→              ? ` • ${formatTimestamp(journal.created_at)}`
226→              : ''}
227→          </Text>
228→          <Text style={styles.body}>{bodyText}</Text>
229→
230→          <View style={styles.actionRow}>
231→            <Pressable
232→              onPress={() => likeMutation.mutate()}
233→              disabled={likeMutation.isPending}
234→              style={({pressed}) => [
235→                styles.actionPill,
236→                journal.has_liked && styles.actionPillActive,
237→                pressed && styles.actionPillPressed,
238→              ]}>
239→              <Text
240→                style={[
241→                  styles.actionText,
242→                  journal.has_liked && styles.actionTextActive,
243→                ]}>
244→                {`${journal.has_liked ? 'Unlike' : 'Like'} (${likeCount})`}
245→              </Text>
246→            </Pressable>
247→
248→            <Pressable
249→              onPress={() => bookmarkMutation.mutate()}
250→              disabled={bookmarkMutation.isPending}
251→              style={({pressed}) => [
252→                styles.actionPill,
253→                journal.has_bookmarked && styles.actionPillActive,
254→                pressed && styles.actionPillPressed,
255→              ]}>
256→              <Text
257→                style={[
258→                  styles.actionText,
259→                  journal.has_bookmarked && styles.actionTextActive,
260→                ]}>
261→                {`${journal.has_bookmarked ? 'Bookmarked' : 'Bookmark'} (${bookmarkCount})`}
262→              </Text>
263→            </Pressable>
264→          </View>
265→
266→          <Text style={styles.meta}>{`Comments (${commentCount})`}</Text>
267→        </View>
268→      )}
269→
270→      {!!journal && (
271→        <View style={styles.card}>
272→          <Text style={styles.sectionTitle}>Repost</Text>
273→          <TextInput
274→            value={repostCaption}
275→            onChangeText={setRepostCaption}
276→            placeholder="Add an optional caption"
277→            placeholderTextColor={colors.textMuted}
278→            style={styles.input}
279→            maxLength={280}
280→            multiline
281→          />
282→          <PrimaryButton
283→            label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
284→            onPress={() => repostMutation.mutate()}
285→            disabled={repostMutation.isPending}
286→          />
287→        </View>
288→      )}
289→
290→      <View style={styles.card}>
291→        <Text style={styles.sectionTitle}>Comments</Text>
292→        {commentsQuery.isLoading ? (
293→          <View style={styles.loadingRow}>
294→            <ActivityIndicator color={colors.accent} />
295→            <Text style={styles.loadingText}>Loading comments...</Text>
296→          </View>
297→        ) : comments.length === 0 ? (
298→          <Text style={styles.meta}>No comments yet.</Text>
299→        ) : (
300→          comments.map(comment => (
301→            <View key={comment.id} style={styles.commentCard}>
302→              <Text style={styles.commentAuthor}>
303→                {comment.users?.name || 'User'}
304→              </Text>
305→              <Text style={styles.commentBody}>{comment.comment || ''}</Text>
306→              <Text style={styles.commentTime}>
307→                {formatTimestamp(comment.created_at)}
308→              </Text>
309→            </View>
310→          ))
311→        )}
312→
313→        {!token ? (
314→          <Text style={styles.meta}>Log in to leave a comment.</Text>
315→        ) : (
316→          <>
317→            <TextInput
318→              value={commentInput}
319→              onChangeText={setCommentInput}
320→              placeholder="Write a comment"
321→              placeholderTextColor={colors.textMuted}
322→              style={styles.input}
323→              maxLength={200}
324→              multiline
325→            />
326→            <PrimaryButton
327→              label={
328→                addCommentMutation.isPending ? 'Posting...' : 'Post Comment'
329→              }
330→              onPress={() => addCommentMutation.mutate()}
331→              disabled={commentInput.trim().length === 0 || addCommentMutation.isPending}
332→            />
333→          </>
334→        )}
335→      </View>
336→    </Screen>
337→  );
338→}
