 31→export function JournalEditorScreen({navigation}: Props) {
 32→  const {session} = useAuth();
 33→  const editorRef = useRef<RichEditor>(null);
 34→  const [title, setTitle] = useState('');
 35→  const [html, setHtml] = useState('');
 36→
 37→  const canSave = useMemo(
 38→    () => title.trim().length > 0 && stripHtml(html).length > 0,
 39→    [html, title],
 40→  );
 41→
 42→  const saveMutation = useMutation({
 43→    mutationFn: async () => {
 44→      const token = session?.access_token;
 45→      if (!token) {
 46→        throw new Error('Authentication token missing');
 47→      }
 48→
 49→      return mobileApi.saveJournal(token, {
 50→        title: title.trim(),
 51→        plainText: stripHtml(html),
 52→        html,
 53→      });
 54→    },
 55→    onSuccess: () => {
 56→      queryClient.invalidateQueries({queryKey: ['feed']});
 57→      Alert.alert('Saved', 'Journal created successfully.');
 58→      navigation.goBack();
 59→    },
 60→    onError: error => {
 61→      Alert.alert(
 62→        'Save failed',
 63→        error instanceof Error ? error.message : 'Unknown error',
 64→      );
 65→    },
 66→  });
 67→
 68→  return (
 69→    <Screen>
 70→      <Text style={styles.title}>Write Journal</Text>
 71→
 72→      <TextInput
 73→        placeholder="Title"
 74→        placeholderTextColor={colors.textMuted}
 75→        value={title}
 76→        onChangeText={setTitle}
 77→        style={styles.input}
 78→      />
 79→
 80→      <RichEditor
 81→        ref={editorRef}
 82→        style={styles.editor}
 83→        placeholder="Write your thoughts..."
 84→        initialHeight={220}
 85→        onChange={setHtml}
 86→        editorStyle={richEditorStyle}
 87→      />
 88→
 89→      <RichToolbar
 90→        editor={editorRef}
 91→        actions={[
 92→          actions.setBold,
 93→          actions.setItalic,
 94→          actions.setUnderline,
 95→          actions.insertBulletsList,
 96→          actions.insertOrderedList,
 97→        ]}
 98→        selectedIconTint={colors.accent}
 99→        iconTint={colors.textMuted}
100→        style={styles.toolbar}
101→      />
102→
103→      <PrimaryButton
104→        label="Save Journal"
105→        onPress={() => saveMutation.mutate()}
106→        loading={saveMutation.isPending}
107→        disabled={!canSave}
108→      />
109→    </Screen>
110→  );
