 37→  const libraryMutation = useMutation({
 38→    mutationFn: () => storyApi.toggleLibrary(token ?? '', storyId),
 39→    onSuccess: () => {
 40→      queryClient.invalidateQueries({queryKey: ['story', storyId]});
 41→      queryClient.invalidateQueries({queryKey: ['stories-library']});
 42→    },
 43→  });
