 36→export function StoryEditorScreen({route, navigation}: Props) {
 37→  const storyId = route.params?.storyId;
 38→  const isEdit = Boolean(storyId);
 39→  const {session} = useAuth();
 40→  const token = session?.access_token ?? '';
 41→
 42→  const storyQuery = useQuery({
 43→    queryKey: ['story-editor', storyId],
 44→    enabled: isEdit && !!storyId,
 45→    queryFn: () => storyApi.getStoryById(storyId ?? '', token),
 46→  });
 47→
 48→  const [title, setTitle] = useState('');
 49→  const [description, setDescription] = useState('');
 50→  const [status, setStatus] = useState<StoryStatus>('ongoing');
 51→  const [privacy, setPrivacy] = useState<StoryPrivacy>('public');
 52→  const [tags, setTags] = useState<string[]>([]);
 53→  const [tagInput, setTagInput] = useState('');
 54→
 55→  useEffect(() => {
 56→    if (storyQuery.data) {
 57→      setTitle(storyQuery.data.title || '');
 58→      setDescription(storyQuery.data.description || '');
 59→      setStatus((storyQuery.data.status as StoryStatus) || 'ongoing');
 60→      setPrivacy((storyQuery.data.privacy as StoryPrivacy) || 'public');
 61→      setTags(Array.isArray(storyQuery.data.tags) ? storyQuery.data.tags : []);
 62→    }
 63→  }, [storyQuery.data]);
 64→
 65→  const canSave = useMemo(() => title.trim().length > 0, [title]);
 66→
 67→  const createMutation = useMutation({
 68→    mutationFn: () =>
 69→      storyApi.createStory(token, {
 70→        title,
 71→        description,
 72→        status,
 73→        privacy,
 74→        tags,
 75→      }),
 76→    onSuccess: data => {
 77→      queryClient.invalidateQueries({queryKey: ['stories-dashboard']});
 78→      queryClient.invalidateQueries({queryKey: ['stories-browser']});
 79→      navigation.replace('StoryChapterManager', {storyId: data.id});
 80→    },
 81→    onError: error => {
 82→      Alert.alert(
 83→        'Failed to create story',
 84→        error instanceof Error ? error.message : 'Unknown error',
 85→      );
 86→    },
 87→  });
 88→
 89→  const updateMutation = useMutation({
 90→    mutationFn: () =>
 91→      storyApi.updateStory(token, storyId ?? '', {
 92→        title,
 93→        description,
 94→        status,
 95→        privacy,
 96→        tags,
 97→      }),
 98→    onSuccess: data => {
 99→      queryClient.invalidateQueries({queryKey: ['story', data.id]});
100→      queryClient.invalidateQueries({queryKey: ['stories-dashboard']});
101→      queryClient.invalidateQueries({queryKey: ['stories-browser']});
102→      navigation.replace('StoryChapterManager', {storyId: data.id});
103→    },
104→    onError: error => {
105→      Alert.alert(
106→        'Failed to update story',
107→        error instanceof Error ? error.message : 'Unknown error',
108→      );
109→    },
110→  });
111→
112→  const addTag = (raw: string) => {
113→    const trimmed = raw.trim();
114→    if (!trimmed) {
115→      return;
116→    }
117→    if (tags.includes(trimmed)) {
118→      setTagInput('');
119→      return;
120→    }
121→    if (tags.length >= 10) {
122→      return;
123→    }
124→    setTags(current => [...current, trimmed]);
125→    setTagInput('');
126→  };
127→
128→  const removeTag = (tag: string) => {
129→    setTags(current => current.filter(item => item !== tag));
130→  };
131→
132→  const onSave = () => {
133→    if (!token) {
134→      Alert.alert('Login required', 'Sign in to save stories.');
135→      return;
136→    }
137→
138→    if (isEdit) {
139→      updateMutation.mutate();
140→    } else {
141→      createMutation.mutate();
142→    }
143→  };
144→
145→  return (
146→    <Screen scroll={false}>
147→      <ScrollView contentContainerStyle={styles.content}>
148→        <Text style={styles.title}>{isEdit ? 'Edit Story' : 'New Story'}</Text>
149→
150→        <Text style={styles.label}>Title</Text>
151→        <TextInput
152→          value={title}
153→          onChangeText={setTitle}
154→          maxLength={200}
155→          placeholder="Give your story a title"
156→          placeholderTextColor={colors.textMuted}
157→          style={styles.input}
158→        />
159→
160→        <Text style={styles.label}>Description</Text>
161→        <TextInput
162→          value={description}
163→          onChangeText={setDescription}
164→          maxLength={2000}
165→          multiline
166→          placeholder="What is your story about?"
167→          placeholderTextColor={colors.textMuted}
168→          style={[styles.input, styles.multiline]}
169→        />
170→
171→        <Text style={styles.label}>Status</Text>
172→        <View style={styles.choiceRow}>
173→          {(['ongoing', 'completed', 'hiatus'] as StoryStatus[]).map(item => (
174→            <PrimaryButton
175→              key={item}
176→              label={item}
177→              onPress={() => setStatus(item)}
178→              kind={status === item ? 'primary' : 'secondary'}
179→            />
180→          ))}
181→        </View>
182→
183→        <Text style={styles.label}>Privacy</Text>
184→        <View style={styles.choiceRow}>
185→          {(['public', 'private'] as StoryPrivacy[]).map(item => (
186→            <PrimaryButton
187→              key={item}
188→              label={item}
189→              onPress={() => setPrivacy(item)}
190→              kind={privacy === item ? 'primary' : 'secondary'}
191→            />
192→          ))}
193→        </View>
194→
195→        <Text style={styles.label}>{`Tags (${tags.length}/10)`}</Text>
196→        <View style={styles.tagsWrap}>
197→          {tags.map(tag => (
198→            <Pressable key={tag} onPress={() => removeTag(tag)} style={styles.tagPill}>
199→              <Text style={styles.tagText}>{`#${tag} ×`}</Text>
200→            </Pressable>
201→          ))}
202→        </View>
203→        <TextInput
204→          value={tagInput}
205→          onChangeText={setTagInput}
206→          onSubmitEditing={() => addTag(tagInput)}
207→          placeholder="Add tag and press enter"
208→          placeholderTextColor={colors.textMuted}
209→          style={styles.input}
210→        />
211→        <View style={styles.tagsWrap}>
212→          {TAG_SUGGESTIONS.filter(tag => !tags.includes(tag))
213→            .slice(0, 8)
214→            .map(tag => (
215→              <Pressable key={tag} onPress={() => addTag(tag)} style={styles.suggestion}>
216→                <Text style={styles.suggestionText}>{`+ ${tag}`}</Text>
217→              </Pressable>
218→            ))}
219→        </View>
220→
221→        <PrimaryButton
222→          label={isEdit ? 'Save Story' : 'Create Story'}
223→          onPress={onSave}
224→          disabled={!canSave}
225→          loading={createMutation.isPending || updateMutation.isPending}
226→        />
227→      </ScrollView>
228→    </Screen>
229→  );
230→}
