  1→import React, {useEffect, useMemo, useRef, useState} from 'react';
  2→import {Alert, StyleSheet, Text, TextInput} from 'react-native';
  3→import {useMutation, useQuery} from '@tanstack/react-query';
  4→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  5→import {actions, RichEditor, RichToolbar} from 'react-native-pell-rich-editor';
  6→import {Screen} from '../../components/Screen';
  7→import {PrimaryButton} from '../../components/PrimaryButton';
  8→import {storyApi} from '../../lib/api/storyApi';
  9→import {
 10→  extractPlainTextFromLexical,
 11→  stripHtml,
 12→  toLexicalFromPlainText,
 13→} from '../../lib/content/lexical';
 14→import {useAuth} from '../../features/auth/AuthProvider';
 15→import {queryClient} from '../../lib/queryClient';
 16→import {colors} from '../../theme/colors';
 17→import type {RootStackParamList} from '../../navigation/types';
